using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change #2: EF 9 changed id format from "EntityType|Key" to "EntityType-Key".
            // Existing documents use "Blog|1", so restore the old separator.
            entity.HasIdProperty().HasIdValueGenerationStrategy(
                CosmosIdValueGenerationStrategy.PipeDelimited);

            // Breaking change #3: Cosmos DB does not support indexes in the EF sense.
            // EF 9 now throws instead of silently ignoring. Remove the HasIndex call.
        });
    }
}
