using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1 – Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so pin the old JSON property name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2 – id no longer contains the discriminator value.
            // Existing documents have id in "Blog|<key>" format, so restore the old behavior.
            entity.HasDiscriminatorInJsonId();

            // Breaking change #3 – Key property is now mapped directly to JSON "id",
            // removing the shadow __id property. Existing documents still have the
            // separate __id shadow property, so restore the old behavior.
            entity.HasShadowId();

            // Breaking change #4 – HasIndex now throws for Cosmos (was silently ignored).
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

