class SyncJob
{
    // Breaking change #5 – Sync I/O is no longer supported by the Cosmos provider.
    // ToList() / SaveChanges() now throw. Use async equivalents instead.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();

        // Breaking change #6 – Raw SQL: if you pinned the discriminator name back
        // to "Discriminator" (as done in BlogContext), existing raw SQL is fine.
        // Otherwise, update queries:
        //   OLD: SELECT * FROM c WHERE c.Discriminator = 'Blog'
        //   NEW: SELECT VALUE c FROM root c WHERE c["$type"] = 'Blog'
        //
        // Breaking change #7 – SQL queries must now project with VALUE modifier:
        //   OLD: SELECT c["Name"] FROM root c
        //   NEW: SELECT VALUE c["Name"] FROM root c
    }
}

